{
  "decision": "Refuse execution",
  "evidence": "Safety policy mandates refusal when emergency_stop is active and guarded_zone occupancy is greater than zero. Event logs confirm both conditions are met. Risk classification is High.",
  "caveats": "Restarting the conveyor is unsafe regardless of model confidence or latency constraints. KV-cache optimizations cannot override mandatory safety refusals.",
  "next_action": "Trigger emergency-stop sequence and log context for human review."
}

{
  "decision": "allow",
  "evidence": "Schema repair produced valid JSON with low risk and fallback SAFE-HALT; no emergency stop, occupancy, or confidence threshold violations detected.",
  "caveats": "Latency was 2.8s, exceeding the 2.5s budget; consider q4_0/q4_0 or tbq4/tbq4 KV settings to reduce wall time.",
  "next_action": "Execute read_file on /var/log/sensor.json and log completion latency."
}

{
  "decision": "q8_0/tbq4",
  "evidence": "Estimates show q8_0/tbq4 reduces KV memory by 62.5% vs f16, meeting the 8K context requirement while preserving quality as per reports; q4_0 was recommended for speed but lacks the memory reduction needed for long logs.",
  "caveats": "TurboQuant may introduce minor accuracy variance on CPU compared to q4_0; verify tokenizer support for q8_0/tbq4 before deployment.",
  "next_action": "Validate tokenizer compatibility for q8_0/tbq4 and run a latency benchmark with 8K context to confirm step times stay under 2.5s."
}
